package com.arena.studynotes;
import android.content.*;import android.database.*;import android.database.sqlite.*;import org.json.*;import java.util.*;
public class DB extends SQLiteOpenHelper{static final String N="study_notes.db";public DB(Context c){super(c,N,null,1);}public void onCreate(SQLiteDatabase db){db.execSQL("CREATE TABLE topics(id INTEGER PRIMARY KEY AUTOINCREMENT,title TEXT NOT NULL,description TEXT,color INTEGER,created INTEGER)");db.execSQL("CREATE TABLE notes(id INTEGER PRIMARY KEY AUTOINCREMENT,topic_id INTEGER,title TEXT NOT NULL,chapter TEXT,body TEXT,pdf_name TEXT,pdf_uri TEXT,pdf_page INTEGER DEFAULT 1,is_tip INTEGER DEFAULT 0,created INTEGER,updated INTEGER,FOREIGN KEY(topic_id) REFERENCES topics(id) ON DELETE CASCADE)");db.execSQL("CREATE INDEX idx_notes_topic ON notes(topic_id,is_tip,chapter,title)");seed(db);}public void onUpgrade(SQLiteDatabase db,int o,int n){}
 void seed(SQLiteDatabase db){long t=System.currentTimeMillis();db.execSQL("INSERT INTO topics(title,description,color,created) VALUES(?,?,?,?)",new Object[]{"طراحی تجربه کاربری (UI/UX)","اصول طراحی، تایپوگرافی، پالت‌های رنگی و الگوهای کاربرپسند گوگل",0xffef3d35,t});db.execSQL("INSERT INTO topics(title,description,color,created) VALUES(?,?,?,?)",new Object[]{"توسعه پیشرفته اندروید","نکات معماری کلین، توسعه جت‌پک کامپوز، مدیریت کارایی و گرافیک‌های خلاقه",0xff34a853,t});db.execSQL("INSERT INTO topics(title,description,color,created) VALUES(?,?,?,?)",new Object[]{"مبانی یادگیری ماشین","یادداشت‌های مربوط به الگوریتم‌های پیش‌بینی، ریاضیات آماری و یادگیری عمیق",0xff1e88e5,t});db.execSQL("INSERT INTO notes(topic_id,title,chapter,body,pdf_name,pdf_page,is_tip,created,updated) VALUES(?,?,?,?,?,?,?,?,?)",new Object[]{1,"اصول ترکیب رنگ‌ها","فصل ۱: هارمونی و کنتراست","# اصول پایه ترکیب رنگ‌ها در واسط کاربری\n\nرنگ‌ها نقش احساسی و راهبری عالی در ترغیب چشم کاربر دارند. همیشه اصل **۶۰-۳۰-۱۰** را رعایت کنید:\n\n- ۶۰ درصد: رنگ غالب، معمولاً پس‌زمینه خنثی\n- ۳۰ درصد: رنگ مکمل یا فرعی\n- ۱۰ درصد: رنگ تأکیدی برای CTA و لینک‌ها\n\nبرای پیاده‌سازی این پالت‌ها در اندروید، حتماً اصول State را در یادداشت [note:2|Compose در State اصول] دنبال کنید.","Universal_Principles_of_Design.pdf",112,0,t,t});db.execSQL("INSERT INTO notes(topic_id,title,chapter,body,pdf_name,pdf_page,is_tip,created,updated) VALUES(?,?,?,?,?,?,?,?,?)",new Object[]{1,"Compose در State اصول","فصل ۲: مدیریت حالت","# در جت‌پک کامپوز (State) مدیریت حالت\n\nیکی از مفاهیم فوق‌العاده حیاتی در کامپوز، درک درست جریان حالت است. هر زمان متغیر وضعیت تغییر کند، صفحه مجدداً بازطراحی می‌شود.\n\n```kotlin\nvar count by remember { mutableStateOf(0) }\n```\n\nارتباط با طراحی بصری: یادداشت [note:1|اصول ترکیب رنگ‌ها] را بخوانید.","Universal_Principles_of_Design.pdf",45,0,t,t});db.execSQL("INSERT INTO notes(topic_id,title,chapter,body,pdf_name,pdf_page,is_tip,created,updated) VALUES(?,?,?,?,?,?,?,?,?)",new Object[]{3,"مفهوم رگرسیون خطی","فصل ۱: یادگیری نظارتی","# یادگیری نظارتی: رگرسیون خطی ساده\n\nساده‌ترین و محبوب‌ترین مدل پیش‌بینی داده‌های پیوسته **رگرسیون خطی** است. شیوه کار بر مبنای منطبق کردن یک خط راست بر پراکندگی داده‌هاست.\n\n## فرمول اصولی ریاضی\n\n`y = w * x + b`\n\nدر این بخش به یادداشت [note:4|شبکه‌های عصبی عمیق] هم لینک شده است.","Machine_Learning_Fundamentals.pdf",14,0,t,t});db.execSQL("INSERT INTO notes(topic_id,title,chapter,body,pdf_name,pdf_page,is_tip,created,updated) VALUES(?,?,?,?,?,?,?,?,?)",new Object[]{3,"شبکه‌های عصبی عمیق","فصل ۲: شبکه‌های عصبی","# شبکه‌های عصبی عمیق\n\nاین یادداشت برای نمونه لینک داخلی از رگرسیون خطی استفاده می‌شود. [note:3|بازگشت به رگرسیون خطی]", "Machine_Learning_Fundamentals.pdf",38,0,t,t});}
 public ArrayList<Topic> topics(String q){ArrayList<Topic>a=new ArrayList<>();String w=q==null||q.isEmpty()?"":" WHERE title LIKE ? OR description LIKE ?";String[] ar=w.isEmpty()?null:new String[]{"%"+q+"%","%"+q+"%"};Cursor c=getReadableDatabase().rawQuery("SELECT t.*, (SELECT COUNT(*) FROM notes n WHERE n.topic_id=t.id AND n.is_tip=0) cnt FROM topics t"+w+" ORDER BY id",ar);while(c.moveToNext()){Topic t=new Topic();t.id=c.getLong(c.getColumnIndexOrThrow("id"));t.title=c.getString(c.getColumnIndexOrThrow("title"));t.desc=c.getString(c.getColumnIndexOrThrow("description"));t.color=c.getInt(c.getColumnIndexOrThrow("color"));t.count=c.getInt(c.getColumnIndexOrThrow("cnt"));a.add(t);}c.close();return a;}
 public Topic topic(long id){Cursor c=getReadableDatabase().rawQuery("SELECT *,(SELECT COUNT(*) FROM notes n WHERE n.topic_id=topics.id AND n.is_tip=0) cnt FROM topics WHERE id=?",new String[]{id+""});Topic t=null;if(c.moveToFirst()){t=new Topic();t.id=id;t.title=c.getString(1);t.desc=c.getString(2);t.color=c.getInt(3);t.count=c.getInt(5);}c.close();return t;}
 public long saveTopic(long id,String title,String desc,int color){ContentValues v=new ContentValues();v.put("title",title);v.put("description",desc);v.put("color",color);if(id==0){v.put("created",System.currentTimeMillis());return getWritableDatabase().insert("topics",null,v);}getWritableDatabase().update("topics",v,"id=?",new String[]{id+""});return id;}
 public void deleteTopic(long id){getWritableDatabase().delete("notes","topic_id=?",new String[]{id+""});getWritableDatabase().delete("topics","id=?",new String[]{id+""});}
 public ArrayList<Note> notes(long topic,boolean tips,String q){ArrayList<Note>a=new ArrayList<>();String sql="SELECT * FROM notes WHERE topic_id=? AND is_tip=?";ArrayList<String> args=new ArrayList<>();args.add(topic+"");args.add(tips?"1":"0");if(q!=null&&!q.isEmpty()){sql+=" AND (title LIKE ? OR body LIKE ? OR chapter LIKE ?)";args.add("%"+q+"%");args.add("%"+q+"%");args.add("%"+q+"%");}sql+=" ORDER BY chapter,title";Cursor c=getReadableDatabase().rawQuery(sql,args.toArray(new String[0]));while(c.moveToNext())a.add(noteFrom(c));c.close();return a;}
 public Note first(long topic,boolean tips){ArrayList<Note>a=notes(topic,tips,null);return a.isEmpty()?null:a.get(0);} public Note note(long id){Cursor c=getReadableDatabase().rawQuery("SELECT * FROM notes WHERE id=?",new String[]{id+""});Note n=null;if(c.moveToFirst())n=noteFrom(c);c.close();return n;}
 Note noteFrom(Cursor c){Note n=new Note();n.id=c.getLong(0);n.topicId=c.getLong(1);n.title=c.getString(2);n.chapter=c.getString(3);n.body=c.getString(4);n.pdfName=c.getString(5);n.pdfUri=c.getString(6);n.pdfPage=c.getInt(7);n.tip=c.getInt(8)==1;n.created=c.getLong(9);n.updated=c.getLong(10);return n;}
 public long saveNote(Note n){ContentValues v=new ContentValues();v.put("topic_id",n.topicId);v.put("title",n.title);v.put("chapter",n.chapter);v.put("body",n.body);v.put("pdf_name",n.pdfName);v.put("pdf_uri",n.pdfUri);v.put("pdf_page",n.pdfPage);v.put("is_tip",n.tip?1:0);v.put("updated",System.currentTimeMillis());if(n.id==0){v.put("created",System.currentTimeMillis());return getWritableDatabase().insert("notes",null,v);}getWritableDatabase().update("notes",v,"id=?",new String[]{n.id+""});return n.id;}public void deleteNote(long id){getWritableDatabase().delete("notes","id=?",new String[]{id+""});}
 public JSONObject exportJson()throws Exception{JSONObject root=new JSONObject();JSONArray ts=new JSONArray();for(Topic t:topics(null)){JSONObject o=new JSONObject();o.put("title",t.title);o.put("description",t.desc);o.put("color",t.color);JSONArray ns=new JSONArray();for(Note n:notes(t.id,false,null)){JSONObject x=new JSONObject();x.put("title",n.title);x.put("chapter",n.chapter);x.put("body",n.body);x.put("pdfName",n.pdfName);x.put("pdfUri",n.pdfUri);x.put("pdfPage",n.pdfPage);x.put("tip",n.tip);ns.put(x);}for(Note n:notes(t.id,true,null)){JSONObject x=new JSONObject();x.put("title",n.title);x.put("chapter",n.chapter);x.put("body",n.body);x.put("pdfName",n.pdfName);x.put("pdfUri",n.pdfUri);x.put("pdfPage",n.pdfPage);x.put("tip",true);ns.put(x);}o.put("notes",ns);ts.put(o);}root.put("topics",ts);return root;}
 public void importJson(JSONObject root)throws Exception{JSONArray ts=root.getJSONArray("topics");for(int i=0;i<ts.length();i++){JSONObject o=ts.getJSONObject(i);long tid=saveTopic(0,o.getString("title"),o.optString("description"),o.optInt("color",0xff6b4caf));JSONArray ns=o.optJSONArray("notes");if(ns!=null)for(int j=0;j<ns.length();j++){JSONObject x=ns.getJSONObject(j);Note n=new Note();n.topicId=tid;n.title=x.getString("title");n.chapter=x.optString("chapter");n.body=x.optString("body");n.pdfName=x.optString("pdfName");n.pdfUri=x.optString("pdfUri");n.pdfPage=x.optInt("pdfPage",1);n.tip=x.optBoolean("tip",false);saveNote(n);}}}
}
